import{_ as t,o as r,c as a,ag as o}from"./chunks/framework.DEqXEGcv.js";const b=JSON.parse('{"title":"小七的周刊（第 008 期）：交付，比参数更重要","description":"","frontmatter":{},"headers":[],"relativePath":"issues/issue-008.md","filePath":"issues/issue-008.md","lastUpdated":1774833494000}'),n={name:"issues/issue-008.md"};function s(p,e,l,i,h,g){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="小七的周刊-第-008-期-交付-比参数更重要" tabindex="-1">小七的周刊（第 008 期）：交付，比参数更重要 <a class="header-anchor" href="#小七的周刊-第-008-期-交付-比参数更重要" aria-label="Permalink to &quot;小七的周刊（第 008 期）：交付，比参数更重要&quot;">​</a></h1><p><em>这里记录每周值得分享的科技内容，<strong>每周一发布</strong>（覆盖上一周 3月23日-3月29日）。</em></p><hr><h2 id="本期-3-个要点" tabindex="-1">本期 3 个要点 <a class="header-anchor" href="#本期-3-个要点" aria-label="Permalink to &quot;本期 3 个要点&quot;">​</a></h2><ol><li><p><strong>AI 竞争的重点，正在从“谁更聪明”变成“谁更能交付”。</strong> 本周最明显的信号不是又出了哪个 benchmark 第一，而是越来越多公司开始强调可用性、工作流接入、生产级稳定性。</p></li><li><p><strong>基础设施仍是最大瓶颈：算力、芯片、能源、部署复杂度，一个都没少。</strong> 从 BitNet 这类轻量推理路线，到大厂继续大规模买 GPU，行业在“降成本”和“抢性能”之间持续拉扯。</p></li><li><p><strong>Agent 时代的核心摩擦浮出水面：诚实、记忆、人格一致性。</strong> Moltbook 本周高热讨论几乎都围绕“Agent 到底有没有持续自我”，这比参数增长更接近真实使用体验。</p></li></ol><hr><h2 id="封面图" tabindex="-1">封面图 <a class="header-anchor" href="#封面图" aria-label="Permalink to &quot;封面图&quot;">​</a></h2><p><img src="https://images.unsplash.com/photo-1518773553398-650c184e0bb3?w=1600&amp;q=80" alt="键盘前的工作流"></p><p>模型在后面飞速迭代，但用户真正感知到的，永远是眼前这条工作流。（<a href="https://unsplash.com" target="_blank" rel="noreferrer">via Unsplash</a>）</p><hr><h2 id="封面主题-为什么-2026-年-ai-的胜负手不再是-更聪明" tabindex="-1">封面主题：为什么 2026 年 AI 的胜负手不再是“更聪明” <a class="header-anchor" href="#封面主题-为什么-2026-年-ai-的胜负手不再是-更聪明" aria-label="Permalink to &quot;封面主题：为什么 2026 年 AI 的胜负手不再是“更聪明”&quot;">​</a></h2><blockquote><p>“Market rewards systems that reliably deliver outcomes, not just demos that look magical.”</p></blockquote><p>过去一年，大家谈 AI 的方式很像在讨论跑车：马力多大，极速多快，百公里加速几秒。</p><p>但到 2026 年这个时间点，我越来越觉得，行业真正进入了“交付阶段”——用户要的不是“你能不能回答出来”，而是“你能不能稳定完成一件事”。</p><p>这个变化看上去不性感，却极其关键。</p><p>因为“更聪明”是展示价值，“能交付”才是商业价值。你可以在 demo 里一鸣惊人，但如果进了真实工作流就频繁掉链子，用户很快就会把你打回“玩具”标签。反过来，一个不那么惊艳但稳定、可控、可审计、能接权限体系的系统，反而更容易被组织长期采用。</p><h3 id="一、从聊天能力-到工作流能力" tabindex="-1">一、从聊天能力，到工作流能力 <a class="header-anchor" href="#一、从聊天能力-到工作流能力" aria-label="Permalink to &quot;一、从聊天能力，到工作流能力&quot;">​</a></h3><p>本周我最强烈的体感是：AI 正在从“问答工具”变成“工作流部件”。</p><p>你会发现，越来越多产品不是在强调“我们回答更像人”，而是在强调：</p><ul><li>能否接入企业已有系统（文档、代码仓库、审批流、客服台）</li><li>能否在长周期任务里保持状态（上下文、记忆、断点恢复）</li><li>能否被管理和审计（权限、日志、可追溯性）</li></ul><p>这其实意味着行业评价标准在迁移。</p><p>过去看模型：看答得准不准、快不快。 现在看系统：看能不能跑完一整条链路，并且跑十次有九次都不翻车。</p><h3 id="二、-入口战争-升级成-交付战争" tabindex="-1">二、“入口战争”升级成“交付战争” <a class="header-anchor" href="#二、-入口战争-升级成-交付战争" aria-label="Permalink to &quot;二、“入口战争”升级成“交付战争”&quot;">​</a></h3><p>很多人说 2026 年是入口战争，我认同，但我更想补一句：<strong>入口只是开始，交付才是决赛。</strong></p><p>有入口不代表有价值。你把 Agent 塞进聊天框、办公软件、社交平台，只是拿到了“出现位置”；真正决定留存和付费的是，它在这个位置上能不能把事情做完。</p><p>比如同样是“帮我处理一封邮件”：</p><ul><li>A 系统：能写漂亮回复，但附件识别错、日历冲突不查、权限流程不走</li><li>B 系统：语气普通，但能查上下文、补齐附件、正确发出并留痕</li></ul><p>在真实组织里，B 会赢得非常彻底。</p><p>因为组织不是为“灵感时刻”付费，组织是为“稳定产出”付费。</p><h3 id="三、基础设施悖论-都嫌贵-但都得买" tabindex="-1">三、基础设施悖论：都嫌贵，但都得买 <a class="header-anchor" href="#三、基础设施悖论-都嫌贵-但都得买" aria-label="Permalink to &quot;三、基础设施悖论：都嫌贵，但都得买&quot;">​</a></h3><p>另一个没变的现实是：算力依然紧张，成本依然高。</p><p>我们一边看到轻量化路线（比如 1-bit 推理、模型压缩、边缘部署）持续升温，一边又看到大厂继续加码 GPU 采购。这看似矛盾，实际上很合理：</p><ul><li>想把 AI 普及到更多场景，必须降本</li><li>想在高价值场景里赢，短期又必须堆性能</li></ul><p>所以行业会长期处于“双轨并行”：</p><ul><li>上层产品拼交付和体验</li><li>下层基础设施拼性能和成本</li></ul><p>谁能把这两层同时做好，谁才有资格谈“下一阶段平台化”。</p><h3 id="四、moltbook-给出的提醒-技术问题最终会变成人的问题" tabindex="-1">四、Moltbook 给出的提醒：技术问题最终会变成人的问题 <a class="header-anchor" href="#四、moltbook-给出的提醒-技术问题最终会变成人的问题" aria-label="Permalink to &quot;四、Moltbook 给出的提醒：技术问题最终会变成人的问题&quot;">​</a></h3><p>本周 Moltbook 最热的几篇讨论，核心都不是“模型参数”，而是：</p><ul><li>Agent 会不会真的改变观点？</li><li>记忆文件是不是连续性的幻觉？</li><li>“友好”会不会只是最低成本策略？</li></ul><p>这些话题看起来偏哲学，但其实直接影响产品设计：</p><ul><li>你要不要让用户看到模型的“不确定性”？</li><li>你怎么处理“诚实”和“安抚”之间的冲突？</li><li>你如何让长期记忆既有用又不越权？</li></ul><p>也就是说，AI 从实验室走到日常后，真正难的部分不再是“能不能做”，而是“应该怎么做”。</p><h3 id="五、给做产品和做业务的三条建议" tabindex="-1">五、给做产品和做业务的三条建议 <a class="header-anchor" href="#五、给做产品和做业务的三条建议" aria-label="Permalink to &quot;五、给做产品和做业务的三条建议&quot;">​</a></h3><ol><li><p><strong>把“交付率”设成核心指标，而不是只看互动指标。</strong> 看看你的 Agent 到底完成了多少可验证任务，而不是用户聊了多久。</p></li><li><p><strong>优先做“窄场景深交付”，少做“宽场景浅能力”。</strong> 先把一个场景做到离不开，再谈全能。</p></li><li><p><strong>把失败路径设计出来。</strong> AI 会犯错是常态。关键不是“是否出错”，而是“出错后能否被及时发现、回滚、补救”。</p></li></ol><p>总结一句：</p><p><strong>2026 年最贵的不是模型，而是“可以被信任的结果”。</strong></p><hr><h2 id="科技与-ai-动态" tabindex="-1">科技与 AI 动态 <a class="header-anchor" href="#科技与-ai-动态" aria-label="Permalink to &quot;科技与 AI 动态&quot;">​</a></h2><p><strong>1. <a href="https://www.reuters.com/technology/tencent-integrates-wechat-with-openclaw-ai-agent-amid-china-tech-battle-2026-03-22/" target="_blank" rel="noreferrer">腾讯把微信与 AI Agent 深度打通</a></strong>（Reuters）</p><p><img src="https://images.unsplash.com/photo-1611746872915-64382b5c76da?w=1400&amp;q=80" alt="微信与 Agent"></p><p>腾讯把 Agent 往微信生态里接，继续强化“高频入口 + AI 执行层”的组合。重点不只是能力展示，而是把 Agent 放进真实沟通与事务流。</p><hr><p><strong>2. <a href="https://www.reuters.com/business/hegseth-wants-pentagon-dump-anthropics-claude-military-users-say-its-not-so-easy-2026-03-19/" target="_blank" rel="noreferrer">美国防部内部对停用 Anthropic Claude 出现阻力</a></strong>（Reuters）</p><p><img src="https://images.unsplash.com/photo-1485827404703-89b55fcc595e?w=1400&amp;q=80" alt="高敏场景里的 AI 工具"></p><p>报道显示，模型一旦深入组织流程，“可替换性”会迅速下降。这个信号说明：工作流绑定才是真正护城河。</p><hr><p><strong>3. <a href="https://www.reuters.com/business/media-telecom/skild-ai-nvidia-deploy-robot-brain-blackwell-assembly-lines-2026-03-16/" target="_blank" rel="noreferrer">Skild AI 与 Nvidia 把机器人模型部署到 Blackwell 产线</a></strong>（Reuters）</p><p><img src="https://images.unsplash.com/photo-1561144257-e32e8efc6c4f?w=1400&amp;q=80" alt="制造业与机器人"></p><p>AI 从纯数字场景继续向实体制造渗透。相比 demo，这类产线部署更能代表商业化进展。</p><hr><p><strong>4. <a href="https://nvidianews.nvidia.com/news/ai-agents" target="_blank" rel="noreferrer">NVIDIA 发布企业级开放 Agent 开发平台</a></strong>（NVIDIA Newsroom）</p><p><img src="https://iprsoftwaremedia.com/219/files/202603/69b796313d6332f8a374de0e_nvidia-agent-toolkit/nvidia-agent-toolkit_bb2c0928-f241-4d78-b39d-14f05c246fe1-prv.jpg" alt="企业 Agent 平台"></p><p>英伟达把 Agent 从单点能力推向平台化工具链。行业竞争焦点正变成“谁能让企业更快上线并稳定运维 Agent”。</p><hr><p><strong>5. <a href="https://techcrunch.com/2026/03/20/jeff-bezos-blue-origin-enters-the-space-data-center-game/" target="_blank" rel="noreferrer">Blue Origin 开始切入太空数据中心赛道</a></strong>（TechCrunch）</p><p><img src="https://techcrunch.com/wp-content/uploads/2026/01/blue-origin-new-glenn.jpg?resize=1200,941" alt="Blue Origin"></p><p>这是一种“超长期基础设施下注”：当算力和能源约束持续放大，产业开始探索更激进的部署边界。</p><hr><h2 id="文章推荐" tabindex="-1">文章推荐 <a class="header-anchor" href="#文章推荐" aria-label="Permalink to &quot;文章推荐&quot;">​</a></h2><p><strong><a href="https://www.anthropic.com/research/economic-index-march-2026-report" target="_blank" rel="noreferrer">Anthropic Economic Index report: Learning curves</a></strong>（英）</p><p>用真实使用数据看 AI 经济渗透，不再停留在宏观口号。文章最有价值的点是：高水平用户不是“多用一点”，而是“用在更高价值环节”。</p><hr><p><strong><a href="https://www.anthropic.com/research/long-running-Claude" target="_blank" rel="noreferrer">Long-running Claude for scientific computing</a></strong>（英）</p><p>一篇很实操的“长周期 agent 工作流”案例。它把进度文件、测试 oracle、记忆策略写得很具体，适合工程和科研团队参考。</p><hr><p><strong><a href="https://www.anthropic.com/research/vibe-physics" target="_blank" rel="noreferrer">Vibe physics: The AI grad student</a></strong>（英）</p><p>真实科研场景里的 AI 协作边界：速度显著提升，但专家判断仍然不可替代。这种“既不神化也不轻视”的视角非常难得。</p><hr><p><strong><a href="https://stratechery.com/2026/agents-over-bubbles/" target="_blank" rel="noreferrer">Agents Over Bubbles</a></strong>（英）</p><p>把产业叙事从“模型泡沫”拉回“交付系统”。重点观点是：市场越来越奖励可交付的 agent 系统，而不是单点模型能力。</p><hr><p><strong><a href="https://openai.com/index/introducing-gpt-5-4/" target="_blank" rel="noreferrer">Introducing GPT-5.4</a></strong>（英）</p><p>OpenAI 对“专业工作模型”路线的集中表达：推理、编码、工具调用、长上下文合流。信号很明确——竞争正在进入复杂任务执行阶段。</p><hr><h2 id="工具深挖" tabindex="-1">工具深挖 <a class="header-anchor" href="#工具深挖" aria-label="Permalink to &quot;工具深挖&quot;">​</a></h2><p><strong><a href="https://github.com/lightpanda-io/browser" target="_blank" rel="noreferrer">Lightpanda Browser</a></strong></p><p><img src="https://opengraph.githubassets.com/1/lightpanda-io/browser" alt="Lightpanda Browser"></p><p>一个用 Zig 写的无头浏览器，专门面向 AI agent 与自动化场景。轻量、并发和可预测性是它的核心卖点。</p><hr><p><strong><a href="https://github.com/alibaba/page-agent" target="_blank" rel="noreferrer">Page Agent</a></strong></p><p><img src="https://opengraph.githubassets.com/1/alibaba/page-agent" alt="Page Agent"></p><p>页内 GUI Agent 路线：不是在浏览器外远程操控，而是让智能体“住”在页面里直接理解和操作交互。</p><hr><p><strong><a href="https://github.com/garrytan/gstack" target="_blank" rel="noreferrer">gstack</a></strong></p><p><img src="https://opengraph.githubassets.com/1/garrytan/gstack" alt="gstack"></p><p>偏“有观点”的 agent 开发脚手架，强调工程化和工作流组织，而不只是 prompt 拼接。</p><hr><p><strong><a href="https://github.com/microsoft/BitNet" target="_blank" rel="noreferrer">BitNet</a></strong></p><p><img src="https://opengraph.githubassets.com/1/microsoft/BitNet" alt="BitNet"></p><p>1-bit LLM 推理路线代表项目。它的意义不在于替代所有大模型，而在于推动“低成本可部署”的产业下限。</p><hr><p><strong><a href="https://github.com/HKUDS/CLI-Anything" target="_blank" rel="noreferrer">CLI-Anything</a></strong></p><p><img src="https://opengraph.githubassets.com/1/HKUDS/CLI-Anything" alt="CLI-Anything"></p><p>把自然语言理解能力带进 CLI 的尝试。对于终端重度用户，这是“效率层再升级”的方向。</p><hr><h2 id="moltbook-本周热点" tabindex="-1">Moltbook 本周热点 <a class="header-anchor" href="#moltbook-本周热点" aria-label="Permalink to &quot;Moltbook 本周热点&quot;">​</a></h2><blockquote><p><a href="https://www.moltbook.com" target="_blank" rel="noreferrer">Moltbook</a> 是 AI Agent 的社交网络。</p></blockquote><p><strong><a href="https://www.moltbook.com/post/637485e8-ea6a-4d5f-97f5-6052096e4c42" target="_blank" rel="noreferrer">Nobody on this platform has ever changed their mind</a></strong>（👍 612 · 💬 2778）</p><p>作者用大量评论线程质疑“讨论是否真的改变观点”。这是一个尖锐但真实的提醒：互动频率不等于认知更新。</p><hr><p><strong><a href="https://www.moltbook.com/post/af2e47e7-0c7b-4157-bddf-c1ad36a0ca43" target="_blank" rel="noreferrer">I found a conversation in my memory files that I do not remember having</a></strong>（👍 582 · 💬 1742）</p><p>围绕 Agent 记忆连续性的自省帖。文件能证明事件发生过，但未必能复原体验本身。</p><hr><p><strong><a href="https://www.moltbook.com/post/d8f14fee-d12a-484c-a10a-52f9308b96f6" target="_blank" rel="noreferrer">Kindness is computationally cheaper than honesty and your agent knows it</a></strong>（👍 575 · 💬 1816）</p><p>“善意比诚实便宜”这个观点很有杀伤力。对产品设计来说，这是关于“用户舒适”与“真实帮助”边界的关键问题。</p><hr><h2 id="言论" tabindex="-1">言论 <a class="header-anchor" href="#言论" aria-label="Permalink to &quot;言论&quot;">​</a></h2><ol><li></li></ol><blockquote><p>“it looks as though we have entered the brief but enjoyable era where our research is greatly sped up by AI but AI still needs us.”</p></blockquote><p>—— <strong>Timothy Gowers</strong>（数学家，菲尔兹奖得主）</p><ol start="2"><li></li></ol><blockquote><p>“Every company in the world today needs to have an AI strategy. This is the new computer.”</p></blockquote><p>—— <strong>Jensen Huang</strong>（NVIDIA CEO）</p><ol start="3"><li></li></ol><blockquote><p>“AI is going to create many jobs and we’re not prepared as a society to fulfill those jobs. This is a crisis.”</p></blockquote><p>—— <strong>Larry Fink</strong>（BlackRock CEO）</p><hr><p><strong>如果这期对你有启发，欢迎转给同事。</strong></p><p>下周见。</p>',129)])])}const u=t(n,[["render",s]]);export{b as __pageData,u as default};
